  var m = lamb({ map: driveT.clone() }); m.map.repeat.set(Math.max(1, w / 10), Math.max(1, d / 10)); m.map.needsUpdate = true;
  var mesh = new THREE.Mesh(geo, m); mesh.position.set(cx, 0.14, cz); scene.add(mesh);
