  b.position.set(x, h / 2 + 0.1, z); scene.add(b); solidMeshes.push(b); addCollider(x, z, w, d, 'bldg');
  mapBuildings.push({ x: x, z: z, w: w, d: d, h: h, c: '#c9c3b4', pad: true });
