  var s = intShell(spec, { floorM: floorM, wallM: wallM, ceilColor: 0xe8e0d0, bannerLines: ['STARBUCKS'], bannerBg: '#00704a', bannerFg: '#d4b880' });
  var Y = s.Y, cx = s.cx;

