    playShopVoice('STAFF', 'chatQ', 0.7, 2);
    shopTalk = { kind: 'banter', a: staffRef(st[ai]), b: staffRef(st[bi]), phase: 0, t: 1.9, ans: SHOP_BA[(Math.random() * SHOP_BA.length) | 0] };
