  if (c.airborne) { c.slopePitch = Math.atan2(c.cvy, Math.max(4, asp)); c.slopeRoll = (c.slopeRoll || 0) * 0.9; }   // nose tracks the arc
  else { c.slopePitch = Math.atan(gs.gx * fx + gs.gz * fz); c.slopeRoll = -Math.atan(gs.gx * rgx + gs.gz * rgz); }
