  x.strokeStyle = 'rgba(255,236,222,0.95)'; x.lineWidth = 3; x.lineCap = 'round';
  for (var i = 0; i < 6; i++) { var a = i * Math.PI / 3; x.beginPath(); x.moveTo(0, 0); x.lineTo(Math.cos(a) * 30, Math.sin(a) * 30); x.stroke(); }
