// ---------------- Hidden secrets & easter eggs (local-only flavor) ----------
// Additive delight the curious stumble on: hand-authored loot stashes, a
// Konami combo, a rare drifting-balloon ambient. All LOCAL (never on the MP
// wire), null-guarded, no colliders, no per-frame allocation. Effects are
// temporary / reversible. Driven from the main loop + __wc.tick via
// updateSecrets(dt); test hooks live in the __wc export block.

// Deterministic stash coords (authored, NOT load-randomized — a prior
// regression reintroduced load-time Math.random() and broke MP determinism).
// Tucked spots around the town core the curious will find. `mesh` = a subtle
// bobbing gold glint marker, built lazily (no load-order dependency).
var SECRET_STASHES = [
  { x: 86, z: 70, val: 250 },     // behind the RaceTrac (SE corner)
  { x: -162, z: 60, val: 300 },   // SW strip-mall service alley
  { x: -96, z: -126, val: 250 },  // tucked behind Publix (NW)
  { x: 96, z: -78, val: 300 },    // behind Regions Bank (NE)
  { x: -232, z: -118, val: 350 }, // scrub by the middle school
  { x: -305, z: -150, val: 400 }, // far west lake shore
  { x: 250, z: -252, val: 400 },  // deep NE tree line
  { x: 30, z: 96, val: 200 }      // south median nook
];
var stashInit = false, stashGeo = null;
function initStashes() {
  stashInit = true;
  if (typeof THREE === 'undefined' || !scene) return;
  stashGeo = new THREE.OctahedronGeometry(0.22);
  for (var i = 0; i < SECRET_STASHES.length; i++) {
    var s = SECRET_STASHES[i];
    s.taken = false; s.baseY = 0.55;
    var m = new THREE.Mesh(stashGeo, new THREE.MeshBasicMaterial({ color: 0xffe27a, transparent: true, opacity: 0.82 }));
    m.position.set(s.x, s.baseY, s.z);
    scene.add(m);
    s.mesh = m;
  }
}
var STASH_R2 = 4.2;   // walk near a glint to grab it
function collectStash(s) {
  if (s.taken) return;
  s.taken = true;
  if (s.mesh) { scene.remove(s.mesh); if (s.mesh.material && s.mesh.material.dispose) s.mesh.material.dispose(); s.mesh = null; }
  state.money += s.val;
  popup('HIDDEN STASH  +$' + s.val);
  if (typeof sfx === 'function') sfx('cash');
  if (typeof puff === 'function') puff(new THREE.Vector3(s.x, 0.6, s.z), 0xffe27a);
  // little ascending jingle so a find feels rewarding
  beep(880, 0.09, 0.12, 'square'); setTimeout(function () { beep(1320, 0.09, 0.12, 'square'); }, 80); setTimeout(function () { beep(1760, 0.12, 0.12, 'square'); }, 170);
}
// --- Konami combo -> harmless confetti + jingle party. Purely cosmetic and
// self-cleaning (particles despawn) so it never touches gameplay balance.
var confetti = [], confettiGeo = null, confettiMats = null, comboCD = 0;
function ensureConfettiAssets() {
  if (confettiGeo) return;
  confettiGeo = new THREE.PlaneGeometry(0.14, 0.2);
  var cols = [0xff5a5a, 0xffd24a, 0x5ad1ff, 0x6aff8a, 0xff8ad6, 0xffffff];
  confettiMats = [];
  for (var i = 0; i < cols.length; i++) confettiMats.push(new THREE.MeshBasicMaterial({ color: cols[i], side: THREE.DoubleSide }));
}
function burstConfetti() {
  ensureConfettiAssets();
  var cx = player.x, cy = (player.y || 1.5) + 2.4, cz = player.z, n = 46;
  for (var i = 0; i < n; i++) {
    var m = new THREE.Mesh(confettiGeo, confettiMats[(Math.random() * confettiMats.length) | 0]);
    m.position.set(cx + (Math.random() - 0.5) * 1.2, cy, cz + (Math.random() - 0.5) * 1.2);
    m.rotation.set(Math.random() * 6.28, Math.random() * 6.28, Math.random() * 6.28);
    scene.add(m);
    confetti.push({ mesh: m, life: 2.6, vx: (Math.random() - 0.5) * 3.4, vy: 2.2 + Math.random() * 2.6, vz: (Math.random() - 0.5) * 3.4, spin: (Math.random() - 0.5) * 9 });
  }
}
function updateConfetti(dt) {
  if (comboCD > 0) comboCD -= dt;
  for (var i = confetti.length - 1; i >= 0; i--) {
    var p = confetti[i]; p.life -= dt; p.vy -= 5.5 * dt;
    p.mesh.position.x += p.vx * dt; p.mesh.position.y += p.vy * dt; p.mesh.position.z += p.vz * dt;
    p.mesh.rotation.z += p.spin * dt; p.mesh.rotation.x += p.spin * 0.6 * dt;
    if (p.mesh.position.y < 0.05) { p.mesh.position.y = 0.05; p.vy = 0; p.vx *= 0.68; p.vz *= 0.68; }
    if (p.life <= 0) { scene.remove(p.mesh); confetti.splice(i, 1); }   // shared mats, no dispose
  }
}
function triggerParty() {
  if (comboCD > 0) return false;
  comboCD = 4;
  burstConfetti();
  var notes = [523, 659, 784, 1047];
  for (var i = 0; i < notes.length; i++) (function (f, d) { setTimeout(function () { beep(f, 0.14, 0.13, 'square'); }, d); })(notes[i], i * 110);
  popup('PARTY MODE!');
  return true;
}
// Classic Konami sequence. A dedicated read-only listener: never preventDefault,
// never writes `keys`, so normal input is untouched. Ignored unless in-play.
var KONAMI = ['ArrowUp', 'ArrowUp', 'ArrowDown', 'ArrowDown', 'ArrowLeft', 'ArrowRight', 'ArrowLeft', 'ArrowRight', 'KeyB', 'KeyA'];
var konamiIdx = 0;
document.addEventListener('keydown', function (e) {
  if (!state.running || state.menu || state.dead) { konamiIdx = 0; return; }
  if (e.code === KONAMI[konamiIdx]) {
    konamiIdx++;
    if (konamiIdx >= KONAMI.length) { konamiIdx = 0; triggerParty(); }
  } else {
    konamiIdx = (e.code === KONAMI[0]) ? 1 : 0;   // allow a fresh restart
  }
});

// --- Rare ambient surprise: a lost cluster of party balloons drifts up and
// away over town. Cosmetic, cheap, on a multi-minute cooldown. Reuses the
// game's soft lambert look; despawns on its own when it clears the skyline.
var balloons = [], balloonGeo = null, balloonStrGeo = null;
var balloonCD = 130 + Math.random() * 90;   // first check well after boot
function ensureBalloonGeo() {
  if (balloonGeo) return;
  balloonGeo = new THREE.SphereGeometry(0.5, 10, 8);
  balloonStrGeo = new THREE.CylinderGeometry(0.015, 0.015, 1.4, 4);
}
function spawnBalloonCluster() {
  ensureBalloonGeo();
  var ang = Math.random() * Math.PI * 2, dist = 16 + Math.random() * 12;
  var ox = player.x + Math.cos(ang) * dist, oz = player.z + Math.sin(ang) * dist;
  var cols = [0xff5a5a, 0x5aa0ff, 0xffd24a, 0x6aff8a, 0xff8ad6, 0xb07aff];
  var n = 3 + (Math.random() * 3 | 0);
  for (var i = 0; i < n; i++) {
    var g = new THREE.Group();
    var bod = new THREE.Mesh(balloonGeo, lamb({ color: cols[(Math.random() * cols.length) | 0] }));
    bod.scale.set(0.82, 1.0, 0.82);
    g.add(bod);
    var str = new THREE.Mesh(balloonStrGeo, lamb({ color: 0x333333 }));
    str.position.y = -1.1; g.add(str);
    g.position.set(ox + (Math.random() - 0.5) * 2.2, 3 + Math.random() * 2, oz + (Math.random() - 0.5) * 2.2);
    scene.add(g);
    balloons.push({ g: g, vy: 1.4 + Math.random() * 0.8, ph: Math.random() * 6.28, swx: (Math.random() - 0.5) * 0.6, swz: (Math.random() - 0.5) * 0.6 });
  }
  // soft ascending chime the moment they appear
  beep(660, 0.16, 0.06, 'sine'); setTimeout(function () { beep(880, 0.18, 0.055, 'sine'); }, 140);
}
function disposeBalloon(b) { scene.remove(b.g); b.g.traverse(function (o) { if (o.material && o.material.dispose) o.material.dispose(); }); }
function updateBalloons(dt) {
  if (!inside) {
    balloonCD -= dt;
    if (balloonCD <= 0) { balloonCD = 150 + Math.random() * 180; if (Math.random() < 0.5) spawnBalloonCluster(); }
  }
  for (var i = balloons.length - 1; i >= 0; i--) {
    var b = balloons[i]; b.ph += dt;
    b.g.position.y += b.vy * dt;
    b.g.position.x += Math.sin(b.ph) * b.swx * dt;
    b.g.position.z += Math.cos(b.ph * 0.8) * b.swz * dt;
    b.g.rotation.z = Math.sin(b.ph) * 0.12;
    if (b.g.position.y > 46) { disposeBalloon(b); balloons.splice(i, 1); }
  }
}

function updateSecrets(dt) {
  if (!state.running) return;
  if (!stashInit) initStashes();
  // stashes: bob + spin the glint, auto-collect on proximity. Skip while inside
  // an interior (player.x/z can coincide with a surface stash under the map).
  if (!inside) {
    for (var i = 0; i < SECRET_STASHES.length; i++) {
      var s = SECRET_STASHES[i];
      if (s.taken || !s.mesh) continue;
      s.mesh.rotation.y += dt * 1.6;
      s.mesh.position.y = s.baseY + Math.sin(T * 2 + i) * 0.09;
      var dx = player.x - s.x, dz = player.z - s.z;
      if (dx * dx + dz * dz < STASH_R2) collectStash(s);
    }
  }
  updateConfetti(dt);
  updateBalloons(dt);
}

// ---------------- blood decals / scorch marks ----------------
var decals = [];
var decalGeo = new THREE.CircleGeometry(1, 10); decalGeo.rotateX(-Math.PI / 2);
// AI-painted puddle/drip sprites (optional blooddecals.js); alpha planes
var bloodPlaneGeo = new THREE.PlaneGeometry(2, 2); bloodPlaneGeo.rotateX(-Math.PI / 2);
var bloodMats = null, dripMats = null;
function decalMats(urls) {
  return urls.map(function (u) {
    var im = new Image();
    var tx = new THREE.Texture(im);
    tx.magFilter = THREE.NearestFilter; tx.minFilter = THREE.NearestFilter; tx.generateMipmaps = false;
    im.onload = function () { tx.needsUpdate = true; };
    im.src = u;
    // lambert (NOT basic): blood must sit in the scene lighting like the
    // pavement does, and dried blood runs darker than the source art
    return new THREE.MeshLambertMaterial({ map: tx, color: 0x8a8a8a, transparent: true, opacity: 1, depthWrite: false });
  });
}
function pushDecal(m, life) {
  scene.add(m); decals.push({ mesh: m, life: life });
  if (decals.length > 60) { var o = decals.shift(); scene.remove(o.mesh); }
}
function bloodDecal(x, z) {
  var m;
  if (typeof BLOOD_DECALS !== 'undefined') {
    if (!bloodMats) bloodMats = decalMats(BLOOD_DECALS.puddles);
    m = new THREE.Mesh(bloodPlaneGeo, bloodMats[(Math.random() * bloodMats.length) | 0].clone());
    m.scale.setScalar(0.7 + Math.random() * 0.8);
  } else {
    m = new THREE.Mesh(decalGeo, new THREE.MeshBasicMaterial({ color: 0x7a1410, transparent: true, opacity: 0.75, depthWrite: false }));
    m.scale.setScalar(0.8 + Math.random() * 0.9);
  }
  m.position.set(x, 0.165 + Math.random() * 0.004, z); m.rotation.y = Math.random() * Math.PI * 2;
  pushDecal(m, 30);
}
function dripDecal(x, z) {
  var m;
  if (typeof BLOOD_DECALS !== 'undefined') {
    if (!dripMats) dripMats = decalMats(BLOOD_DECALS.drips);
    m = new THREE.Mesh(bloodPlaneGeo, dripMats[(Math.random() * dripMats.length) | 0].clone());
    m.scale.setScalar(0.16 + Math.random() * 0.14);
  } else {
    m = new THREE.Mesh(decalGeo, new THREE.MeshBasicMaterial({ color: 0x6f1210, transparent: true, opacity: 0.7, depthWrite: false }));
    m.scale.setScalar(0.08 + Math.random() * 0.06);
  }
  m.position.set(x, 0.163 + Math.random() * 0.004, z); m.rotation.y = Math.random() * Math.PI * 2;
  pushDecal(m, 18);
}
function scorch(x, z) {
  var m = new THREE.Mesh(decalGeo, new THREE.MeshBasicMaterial({ color: 0x1a1a1a, transparent: true, opacity: 0.7, depthWrite: false }));
  m.scale.setScalar(3.5); m.position.set(x, 0.168, z);
  scene.add(m); decals.push({ mesh: m, life: 40 });
}
// ---- bullet holes (mrft7zm5): small dark pocks stamped on static surfaces
// at the hitscan intersection, oriented to the surface normal. Own capped
// pool (60, oldest recycled) so a firefight can't evict blood/scorch decals.
// Canvas texture (near-black core, ragged edge, subtle chipped rim); shared
// material, depthWrite:false + polygonOffset + tiny normal lift = no z-fight.
var bHoles = [], bHoleMat = null, bHoleGeo = null, bHoleM3 = null;
function bulletHoleTex() {
  var cv = document.createElement('canvas'); cv.width = cv.height = 32;
  var g = cv.getContext('2d');
  g.clearRect(0, 0, 32, 32);
  // ragged dark blob
  g.fillStyle = 'rgba(32,27,22,0.85)';
  for (var i = 0; i < 9; i++) {
    var a = i / 9 * 6.28;
    g.beginPath(); g.arc(16 + Math.cos(a) * 3.4, 16 + Math.sin(a) * 3.4, 3.2 + Math.random() * 2.2, 0, 6.28); g.fill();
  }
  // subtle pale rim — chipped paint/stucco catch-light
  g.strokeStyle = 'rgba(214,204,188,0.4)'; g.lineWidth = 1.4;
  for (i = 0; i < 6; i++) { var a2 = Math.random() * 6.28; g.beginPath(); g.arc(16, 16, 8.6 + Math.random() * 2, a2, a2 + 0.9); g.stroke(); }
  // near-black core
  var rg = g.createRadialGradient(16, 16, 0, 16, 16, 7);
  rg.addColorStop(0, 'rgba(0,0,0,0.96)'); rg.addColorStop(0.6, 'rgba(8,7,6,0.8)'); rg.addColorStop(1, 'rgba(10,8,6,0)');
  g.fillStyle = rg; g.beginPath(); g.arc(16, 16, 7, 0, 6.28); g.fill();
  return new THREE.CanvasTexture(cv);
}
function bulletHole(h) {
  if (!h || !h.face || !h.object) return;
  if (!bHoleMat) {
    bHoleGeo = new THREE.PlaneGeometry(0.16, 0.16);
    bHoleMat = new THREE.MeshBasicMaterial({ map: bulletHoleTex(), transparent: true, depthWrite: false, polygonOffset: true, polygonOffsetFactor: -4, polygonOffsetUnits: -4 });
    bHoleM3 = new THREE.Matrix3();
  }
  var nrm = h.face.normal.clone().applyMatrix3(bHoleM3.getNormalMatrix(h.object.matrixWorld)).normalize();
  var m = new THREE.Mesh(bHoleGeo, bHoleMat);
  m.position.copy(h.point).addScaledVector(nrm, 0.02);
  m.lookAt(h.point.x + nrm.x, h.point.y + nrm.y, h.point.z + nrm.z);
  m.rotateZ(Math.random() * 6.28);   // random roll so repeat hits don't tile
  scene.add(m);
  bHoles.push({ mesh: m, life: 60 });
  if (bHoles.length > 60) { var o = bHoles.shift(); scene.remove(o.mesh); }
}
function updateDecals(dt) {
  for (var bh = bHoles.length - 1; bh >= 0; bh--) {
    bHoles[bh].life -= dt;
    if (bHoles[bh].life <= 0) { scene.remove(bHoles[bh].mesh); bHoles.splice(bh, 1); }
  }
  for (var i = decals.length - 1; i >= 0; i--) {
    var d = decals[i]; d.life -= dt;
    if (d.life < 5) d.mesh.material.opacity = Math.max(0, d.life / 5 * 0.75);
    if (d.life <= 0) { scene.remove(d.mesh); decals.splice(i, 1); }
  }
}

// ---------------- ragdoll kills + explosions ----------------
function killNpcRagdoll(n, dx, dz, power) {
  if (n.state === 'down' || n.state === 'ragdoll' || n.state === 'hidden') return;
  breakNpcChat(n);   // free the chat partner before this one goes flying
  n.state = 'ragdoll'; n.hp = 0;
  if (n.grp) leaveGroup(n);   // #67: detach from its social group before it goes flying
  stopNpcVoice(n.vname);
  if (n.mesh.userData.shadow) n.mesh.userData.shadow.visible = false;
  n.vx = dx * power + (Math.random() - 0.5) * 3;
  n.vz = dz * power + (Math.random() - 0.5) * 3;
  n.vy = 6.5 + Math.random() * 4.5;
  n.airY = 0.2;   // launch from near ground level; vy carries the arc (was 0.9 = a visible ~1m pop the instant they died)
  n.spinX = (Math.random() - 0.5) * 14;
  n.spinZ = (Math.random() - 0.5) * 14;
  sfx('grunt', { x: n.x, z: n.z, range: 60, fem: n.fem });
  for (var i = 0; i < 5; i++) puff(new THREE.Vector3(n.x + (Math.random() - 0.5), 0.8 + Math.random() * 1.2, n.z + (Math.random() - 0.5)), 0xa01212, 'blood');
  bloodDecal(n.x, n.z);
  spawnCash(n.x, n.z, 5 + ((Math.random() * 18) | 0));
  maybeNpcItemDrop(n.x, n.z);
}

var booms = [];
var boomGeo = new THREE.SphereGeometry(1, 10, 8);
function boomAt(x, z, fromNet, creditConn) {
  // creditConn: when a CLIENT's rocket detonates, the host passes their conn
  // so blast kills answer with 'kill' credit like dmgNpc/dmgCop do
  if (!fromNet && typeof netBroadcast === 'function' && net.conns.length) netBroadcast({ t: 'boom', x: x, z: z });
  var mesh = new THREE.Mesh(boomGeo, new THREE.MeshBasicMaterial({ color: 0xff8828, transparent: true, opacity: 0.95 }));
  mesh.position.set(x, 1.5, z); scene.add(mesh);
  booms.push({ mesh: mesh, life: 0.55, max: 0.55 });
  for (var i = 0; i < 9; i++) puff(new THREE.Vector3(x + (Math.random() - 0.5) * 4, 0.8 + Math.random() * 3, z + (Math.random() - 0.5) * 4), i % 2 ? 0x333333 : 0xd86a20);
  scorch(x, z);
  sfx('boom', { x: x, z: z, range: 260 });
  if (!isClient()) {   // kills are host-authoritative; clients get them via snapshot
    for (i = 0; i < npcs.length; i++) {
      var n = npcs[i]; if (n.state === 'down' || n.state === 'ragdoll' || n.state === 'hidden') continue;
      var dx = n.x - x, dz = n.z - z, d = Math.sqrt(dx * dx + dz * dz);
      if (d < 9) {
        killNpcRagdoll(n, dx / (d || 1), dz / (d || 1), 13);
        if (creditConn) { try { creditConn.send({ t: 'kill', kind: 'npc' }); } catch (e) { } }
      }
    }
    for (i = 0; i < cops.length; i++) {
      var cp = cops[i]; if (cp.state === 'down') continue;
      var cdx = cp.x - x, cdz = cp.z - z, cd = Math.sqrt(cdx * cdx + cdz * cdz);
      if (cd < 9) {
        damageCop(cp, 999, cdx / (cd || 1), cdz / (cd || 1), !!creditConn);   // silent when it's a client's kill — the stars are theirs
        if (creditConn && cp.state === 'down') { try { creditConn.send({ t: 'kill', kind: 'cop' }); } catch (e) { } }
      }
    }
    panicNear(x, z, 900);   // survivors within ~30m scatter (aborts sidewalk chats too)
  }
  var pdx = player.x - x, pdz = player.z - z, pd = Math.sqrt(pdx * pdx + pdz * pdz);
  if (pd < 10 && !state.dead) hurtPlayer(Math.round(80 * (1 - pd / 10) + 15), x, z);
  // chain: nearby cars go up too
  if (!isClient()) for (i = 0; i < cars.length; i++) {
    var cx = cars[i];
    if (cx.exploded || cx.stolen || cx.drivenBy) continue;   // player rides never chain silently — their driver can't be told
    var cm = cx.car.group.position;
    if (Math.abs(cm.x - x) < 6 && Math.abs(cm.z - z) < 6) {
      explodeCar(cx);
      if (creditConn) { try { creditConn.send({ t: 'kill', kind: 'car' }); } catch (e) { } }
    }
  }
}
function updateBooms(dt) {
  for (var i = booms.length - 1; i >= 0; i--) {
    var b = booms[i]; b.life -= dt;
    var t = 1 - b.life / b.max;
    b.mesh.scale.setScalar(2 + t * 9);
    b.mesh.material.opacity = Math.max(0, 0.95 * (1 - t));
    if (b.life <= 0) { scene.remove(b.mesh); booms.splice(i, 1); }
  }
}
// returns TRUE only when this call actually starts the wreck (goes berserk or
// first ignites a parked car) — callers gate kill-credit on it so a car already
// berserk/burning/exploded can't be re-credited on every follow-up shot/ram
function goBerserk(c) {
  if (c.berserk || c.burning || c.exploded) return false;
  if (c.parked) {
    // no driver to lose control — a shot-up parked car just catches fire and blows
    c.burning = true; c.burnT = 2.2; c.flameT = 0;
    var pp = c.car.group.position;
    sfx('crash', { x: pp.x, z: pp.z, range: 90 });
    return true;
  }
  c.berserk = true;
  var m = c.car.group;
  var dirx = c.axis === 'x' ? c.dir : 0, dirz = c.axis === 'z' ? c.dir : 0;
  var side = Math.random() < 0.5 ? 1 : -1;                 // veer left or right
  var ang = side * (0.55 + Math.random() * 0.55);          // 30-63 degrees off the road
  var ca = Math.cos(ang), sa = Math.sin(ang);
  var spd = c.speed * 2.2 + 10;
  c.bvx = (dirx * ca - dirz * sa) * spd;
  c.bvz = (dirx * sa + dirz * ca) * spd;
  c.bx = m.position.x; c.bz = m.position.z;
  c.spin = side * (7 + Math.random() * 7);                 // crazy spin
  c.curve = side * (0.08 + Math.random() * 0.18);          // gentle arc — stays headed off the road
  c.boomTimer = 6;
  sfx('crash', { x: m.position.x, z: m.position.z, range: 120 });
  return true;
}
function shoveCar(c, dx, dz, sp) {
  var m2 = c.car.group;
  var d = Math.sqrt(dx * dx + dz * dz) || 1;
  c.shoveT = 1.1;
  c.sx = m2.position.x; c.sz = m2.position.z;
  c.svx = dx / d * sp; c.svz = dz / d * sp;
  c.sspin = (Math.random() < 0.5 ? -1 : 1) * (4 + Math.random() * 5);
}
function igniteCar(c) {
  if (c.burning || c.exploded) return;
  c.burning = true; c.burnT = 5; c.flameT = 0;
  popup2('YOUR CAR IS ON FIRE — GET OUT!');
  sfx('alarm');
}
// ---- burned-out husk (GGBot Car 06): every explosion leaves the wreck at
// the spot until the car respawns (traffic 5 s / lot slot 60 s), so the husk
// can never outlive or duplicate a respawn — explodeCar guards on c.exploded,
// so chain explosions get exactly one husk per car. Per-peer visual in MP
// (like breakables): the host spawns it from explodeCar, clients from the
// snapshot exploded flag in applyWorldSnap.
function spawnHusk(c) {
  if (GG_WRECK_I < 0 || c.husk) return;
  var e = GGBOT_VEHS[GG_WRECK_I];
  var hs = VEH_LEN / e.dims[0];
  var m = new THREE.Mesh(getGGGeo(GG_WRECK_I), getGGMat(GG_WRECK_I, 0));
  m.scale.set(hs, hs, hs);
  var g = c.car.group;
  m.position.set(g.position.x, -0.09, g.position.z);   // slightly sunk into the road
  m.rotation.y = g.rotation.y;                         // aligned to the dead car
  scene.add(m);
  c.husk = m;
}
function removeHusk(c) { if (c.husk) { scene.remove(c.husk); c.husk = null; } }
function explodeCar(c) {
  if (c.exploded) return;
  c.exploded = true; c.berserk = false; c.dmgT = 0; c.burning = false;
  if (c.eng) stopEngine(c);   // a wrecked car makes no engine noise
  var pos = c.car.group.position;
  if (driving === c) {
    // blown out of your own ride
    driving = null;
    radioStop();   // the radio dies with the car
    document.getElementById('crosshair').style.display = '';
    setEquipped(state.equipped);
  }
  boomAt(pos.x, pos.z);
  c.car.group.visible = false;
  spawnHusk(c);
  c.respawnT = c.slot ? 60 : 5;   // lot cars take a minute to "get replaced"
}

// ---------------- rockets ----------------
var rockets = [];
var rocketBodyM = lamb({ color: 0x4a5a3a });
var rocketTipM = lamb({ color: 0xb03024 });
function fireRocket() {
  if (bankRocketCheck()) return;   // rocket into the bank vault door blows it open (no projectile jank underground)
  var dir = new THREE.Vector3();
  camera.getWorldDirection(dir);
  var g = new THREE.Group();
  var body = cyl(0.05, 0.05, 0.45, 8, rocketBodyM, 0, 0, 0); body.rotation.x = Math.PI / 2; g.add(body);
  var tip = cyl(0.001, 0.05, 0.14, 8, rocketTipM, 0, 0, -0.29); tip.rotation.x = -Math.PI / 2; g.add(tip);
  g.add(box(0.02, 0.12, 0.1, rocketBodyM, 0, 0, 0.2));
  g.add(box(0.12, 0.02, 0.1, rocketBodyM, 0, 0, 0.2));
  var start = camera.position.clone().add(dir.clone().multiplyScalar(1.2));
  g.position.copy(start);
  g.lookAt(start.clone().add(dir));
  scene.add(g);
  rockets.push({ mesh: g, x: start.x, y: start.y, z: start.z, dx: dir.x, dy: dir.y, dz: dir.z, life: 6, smokeT: 0 });
  sfx('rocketfire');
}
function detonateRocket(r, i) {
  scene.remove(r.mesh);
  rockets.splice(i, 1);
  boomAt(r.x, r.z);
}
function updateRockets(dt) {
  for (var i = rockets.length - 1; i >= 0; i--) {
    var r = rockets[i];
    var spd = 46;
    r.x += r.dx * spd * dt; r.y += r.dy * spd * dt; r.z += r.dz * spd * dt;
    r.mesh.position.set(r.x, r.y, r.z);
    r.smokeT -= dt;
    if (r.smokeT <= 0) { r.smokeT = 0.035; puff(new THREE.Vector3(r.x - r.dx, r.y - r.dy, r.z - r.dz), 0x999999); }
    r.life -= dt;
    var hit = r.life <= 0 || r.y <= 0.25 || Math.abs(r.x) > HALF || Math.abs(r.z) > HALF;
    if (!hit && r.y < 14) {
      for (var b = 0; b < colliders.length; b++) { var bb = colliders[b]; if (bb.active === false) continue; if (r.x > bb.x0 && r.x < bb.x1 && r.z > bb.z0 && r.z < bb.z1) { hit = true; break; } }
    }
    if (!hit && r.y < 2.4) {
      for (var n = 0; n < npcs.length && !hit; n++) { var nn = npcs[n]; if (nn.state === 'down' || nn.state === 'ragdoll' || nn.state === 'hidden') continue; var dx = nn.x - r.x, dz = nn.z - r.z; if (dx * dx + dz * dz < 1.7) hit = true; }
      for (var cpi = 0; cpi < cops.length && !hit; cpi++) { var cp = cops[cpi]; if (cp.state === 'down') continue; var cdx = cp.x - r.x, cdz = cp.z - r.z; if (cdx * cdx + cdz * cdz < 1.7) hit = true; }
      for (var ci2 = 0; ci2 < cars.length && !hit; ci2++) { var cc = cars[ci2]; if (cc.exploded) continue; var om = cc.car.group.position; if (Math.abs(om.x - r.x) < 2.8 && Math.abs(om.z - r.z) < 2.2) hit = true; }
    }
    if (hit) detonateRocket(r, i);
  }
}

// ---------------- weapon drops ----------------
var drops = [];
function dropMesh(kind) {
  var g = new THREE.Group();
  if (kind === 'pistol') { g.add(box(0.1, 0.12, 0.45, darkMetalM, 0, 0, 0)); g.add(box(0.09, 0.24, 0.13, gripM, 0, -0.14, 0.14)); }
  else if (kind === 'smg') { g.add(box(0.1, 0.13, 0.6, metalM, 0, 0, 0)); g.add(box(0.07, 0.34, 0.1, metalM, 0, -0.2, -0.1)); }
  else if (kind === 'rifle') { g.add(box(0.09, 0.11, 0.95, woodM, 0, 0, 0)); var sc = cyl(0.04, 0.04, 0.3, 8, darkMetalM, 0, 0.1, 0.1); sc.rotation.x = Math.PI / 2; g.add(sc); }
  else if (kind === 'auto') { g.add(box(0.09, 0.12, 0.85, woodM, 0, 0, 0)); var mg = box(0.07, 0.24, 0.11, metalM, 0, -0.15, -0.05); mg.rotation.x = 0.5; g.add(mg); }
  else if (kind === 'raygun') {
    if (hasMeshyProp('raygun')) { var rg = getUfoMesh('raygun', 0.85); rg.position.y = -0.3; g.add(rg); return g; }
    var rb = cyl(0.07, 0.1, 0.5, 8, metalM, 0, 0, 0); rb.rotation.x = Math.PI / 2; g.add(rb);
    g.add(sph(0.09, new THREE.MeshBasicMaterial({ color: 0x66ff88 }), 0, 0, -0.3, 8, 6));
    g.add(box(0.03, 0.2, 0.16, lamb({ color: 0xb02030 }), 0, 0.12, 0.1));
    g.add(box(0.08, 0.2, 0.1, gripM, 0, -0.16, 0.16));
  }
  else if (kind === 'neon_blaster') {   // #78 tinted ray-gun body
    var nb2 = cyl(0.07, 0.1, 0.5, 8, phong({ color: 0x1a2b3a, emissive: 0x1560a0, shininess: 120 }), 0, 0, 0); nb2.rotation.x = Math.PI / 2; g.add(nb2);
    g.add(sph(0.09, new THREE.MeshBasicMaterial({ color: 0x33ffe0 }), 0, 0, -0.3, 8, 6));
    g.add(box(0.03, 0.2, 0.16, new THREE.MeshBasicMaterial({ color: 0xff40d0 }), 0, 0.12, 0.1));
    g.add(box(0.08, 0.2, 0.1, gripM, 0, -0.16, 0.16));
  }
  else if (kind === 'silenced') {   // #78 pistol + suppressor
    g.add(box(0.1, 0.12, 0.45, darkMetalM, 0, 0, 0)); g.add(box(0.09, 0.24, 0.13, gripM, 0, -0.14, 0.14));
    var sup = cyl(0.05, 0.05, 0.34, 10, darkMetalM, 0, 0, -0.36); sup.rotation.x = Math.PI / 2; g.add(sup);
  }
  else if (kind === 'axe') { var ax = (typeof getAxeMesh === 'function') ? getAxeMesh(1.25) : null; if (ax) { g.add(ax); return g; } g.add(box(0.08, 0.9, 0.14, woodM, 0, 0, 0)); g.add(box(0.34, 0.22, 0.06, metalM, 0, 0.42, 0)); }
  else { var tb = cyl(0.09, 0.09, 1.0, 10, rocketBodyM, 0, 0, 0); tb.rotation.x = Math.PI / 2; g.add(tb); }
  return g;
}
// put a gun in a skinned character's right hand (cops, armed remote players).
// kind = null/undefined removes it (holstered). NOTE: must only be called at
// runtime, never during script load — dropMesh's gun materials are vars
// defined below and an early call bakes white default materials in.
function attachHeldGun(g, kind) {
  if (g.userData.heldGun) { g.userData.heldGun.parent.remove(g.userData.heldGun); g.userData.heldGun = null; }
  g.userData.heldKind = null;
  if (!kind || !g.userData.handR) return;
  var gun = dropMesh(kind);
  gun.scale.setScalar(0.85);
  gun.position.set(0.02, 0.06, 0.0);
  gun.rotation.set(1.35, 0.3, 0);   // grip in the fist, barrel continuing the aimed forearm (solved w/ copAimArm angles)
  g.userData.handR.add(gun);
  g.userData.heldGun = gun; g.userData.heldKind = kind;
}
function dropWeapon(kind, x, z) {
  var g = dropMesh(kind);
  g.position.set(x, 0.7, z);
  scene.add(g);
  // the one-per-session alien gun never rots on the pavement
  drops.push({ mesh: g, kind: kind, life: kind === 'raygun' ? 9999 : 120 });
}
function applyDropPickup(kind) {
  if (kind === 'soda') {   // legacy soda-kind drop — route to the grid bag
    if (bagAdd('soda', 1) === 0) { itemToast('soda'); sfx('buy'); }
    return;
  }
  if (!WEAPONS[kind]) return;
  if (state.owned[kind]) {
    var refund = Math.floor((WEAPONS[kind].price || 0) / 2);
    state.money += refund;
    popup(refund ? '+$' + refund + ' (sold ' + WEAPONS[kind].name + ')' : 'Already have a ' + WEAPONS[kind].name);
    if (refund) sfx('cash');
  } else {
    state.owned[kind] = true;
    hotbarAdd(kind);
    popup('Picked up ' + WEAPONS[kind].name);
    sfx('buy');
  }
}
function updateDrops(dt) {
  for (var i = drops.length - 1; i >= 0; i--) {
    var d = drops[i];
    d.mesh.rotation.y += dt * 1.6;
    d.mesh.position.y = 0.7 + Math.sin(T * 2.2 + i) * 0.12;
    var dx = player.x - d.mesh.position.x, dz = player.z - d.mesh.position.z;
    if (!state.dead && dx * dx + dz * dz < 2.6) {
      if (d.net) {
        // host owns drops in multiplayer — ask, and take it when granted
        if (d.pend && T - (d.pendT || 0) > 1.5) d.pend = false;
        if (!d.pend) { d.pend = true; d.pendT = T; netToHost({ t: 'takeDrop', x: d.mesh.position.x, z: d.mesh.position.z }); }
        continue;
      }
      if (d.kind === 'item') {
        var leftIt = bagAdd(d.itemId, 1);
        if (leftIt > 0) { d.bagFull = true; continue; }   // bag full — leave it lying
        itemToast(d.itemId); sfx('buy');
        scene.remove(d.mesh); drops.splice(i, 1);
        continue;
      }
      applyDropPickup(d.kind);
      scene.remove(d.mesh); drops.splice(i, 1);
      continue;
    }
    if (d.net) continue;   // lifetime is the host's call
    d.life -= dt;
    if (d.life <= 0) { scene.remove(d.mesh); drops.splice(i, 1); }
  }
}

// ---------------- grid item inventory (task #57; client-local like interiors) ----
// itemicons.js supplies ITEM_ICONS (alpha PNG data-URLs) + ITEM_DEFS (rows:
// id,name,cat,stackMax,use,hp,value,rarity). The bag is N slots of {id,n}
// stacks. Guarded so the game still boots if the icon bank is missing.
var BAG_SLOTS = 24;                 // 6x4 grid
var ITEM_BANK_OK = (typeof ITEM_DEFS !== 'undefined' && typeof ITEM_ICONS !== 'undefined');
var ITEM_BY_ID = {};
if (ITEM_BANK_OK) for (var _idi = 0; _idi < ITEM_DEFS.length; _idi++) ITEM_BY_ID[ITEM_DEFS[_idi].id] = ITEM_DEFS[_idi];
function itemDef(id) { return ITEM_BY_ID[id] || null; }
state.bag = [];
for (var _bsi = 0; _bsi < BAG_SLOTS; _bsi++) state.bag.push(null);
var bagSel = -1;                    // last-hovered grid slot (for the Q-drop key)

// icon THREE.Texture cache (for the world-pickup sprites)
var itemTexCache = {};
function itemTex(id) {
  if (itemTexCache[id]) return itemTexCache[id];
  var url = ITEM_ICONS && ITEM_ICONS[id];
  var im = new Image();
  var tx = new THREE.Texture(im);
  tx.magFilter = THREE.NearestFilter; tx.minFilter = THREE.NearestFilter; tx.generateMipmaps = false;
  im.onload = function () { tx.needsUpdate = true; };
  if (url) im.src = url;
  itemTexCache[id] = tx;
  return tx;
}
function itemIconHtml(id) { var u = ITEM_ICONS && ITEM_ICONS[id]; return u ? '<img src="' + u + '" style="width:26px;height:26px;vertical-align:middle;margin-right:6px;">' : ''; }
function itemToast(id, n) { var def = itemDef(id); if (!def) return; toast(itemIconHtml(id) + ' Picked up <b>' + def.name + '</b>' + (n > 1 ? ' &times;' + n : ''), 2600); }

function bagCount(id) { var t = 0; for (var i = 0; i < state.bag.length; i++) { var s = state.bag[i]; if (s && s.id === id) t += s.n; } return t; }
// fill matching stacks first, then empty slots; returns the leftover that didn't fit
function bagAdd(id, count) {
  var def = itemDef(id); if (!def) return count || 0;
  var left = (count == null) ? 1 : count, max = def.stackMax || 1, i;
  for (i = 0; i < state.bag.length && left > 0; i++) {
    var s = state.bag[i];
    if (s && s.id === id && s.n < max) { var add = Math.min(max - s.n, left); s.n += add; left -= add; }
  }
  for (i = 0; i < state.bag.length && left > 0; i++) {
    if (!state.bag[i]) { var add2 = Math.min(max, left); state.bag[i] = { id: id, n: add2 }; left -= add2; }
  }
  if (state.menu === 'inv') refreshInvGrid();
  return left;
}
function bagRemove(slot, count) {
  var s = state.bag[slot]; if (!s) return 0;
  var take = (count == null) ? s.n : Math.min(count, s.n);
  s.n -= take; if (s.n <= 0) state.bag[slot] = null;
  if (state.menu === 'inv') refreshInvGrid();
  return take;
}
function bagUse(slot) {
  var s = state.bag[slot]; if (!s) return;
  var def = itemDef(s.id); if (!def) return;
  var u = def.use;
  if (u === 'eat' || u === 'drink' || u === 'med') {
    if (state.hp >= 100) { popup2('Already full HP'); return; }
    state.hp = Math.min(100, state.hp + (def.hp || 0));
    sfx('eat'); popup('+' + (def.hp || 0) + ' HP');
    bagRemove(slot, 1);
  } else if (u === 'sell') {
    toast(itemIconHtml(s.id) + ' Sell your <b>' + def.name + '</b> to the gun dealer for <span style="color:#8ee87f">$' + def.value + '</span>', 3200);
  } else if (u === 'tool') {
    sfx('hit'); toast(itemIconHtml(s.id) + ' The <b>' + def.name + '</b> feels useful…', 2400);
  } else if (u === 'fun') {
    funItem(slot, s, def);
  }
}
var MAGIC8 = ['It is certain', 'Ask again later', 'Doubtful', 'Without a doubt', 'My reply is no', 'Signs point to yes', 'Cannot predict now', 'Outlook good'];
function funItem(slot, s, def) {
  if (def.hp && def.hp > 0) {   // e.g. Fish — edible novelty
    if (state.hp < 100) { state.hp = Math.min(100, state.hp + def.hp); sfx('eat'); popup('+' + def.hp + ' HP'); bagRemove(slot, 1); return; }
  }
  if (s.id === 'magic8') { toast('🎱 The Magic 8-Ball says: <b>' + MAGIC8[(Math.random() * MAGIC8.length) | 0] + '</b>', 3000); return; }
  if (s.id === 'lottery') {
    bagRemove(slot, 1);
    if (Math.random() < 0.15) { var win = 50 + ((Math.random() * 200) | 0); state.money += win; sfx('cash'); toast('🎉 WINNER! The lottery ticket pays <span style="color:#8ee87f">$' + win + '</span>!', 3500); }
    else { sfx('deny'); toast('🎫 Not a winner. Better luck next time.', 2600); }
    return;
  }
  if (s.id === 'firework') {   // pop a cosmetic burst over your head
    bagRemove(slot, 1);
    for (var i = 0; i < 10; i++) puff(new THREE.Vector3(player.x + (Math.random() - 0.5) * 3, EYE + 1.5 + Math.random() * 2, player.z + (Math.random() - 0.5) * 3), i % 2 ? 0xffd23a : 0xff4d6d);
    sfx('boom', { x: player.x, z: player.z, range: 60 });
    toast('🎆 You set off the firework!', 2200);
    return;
  }
  var lines = { rubberduck: 'Squeak! The rubber duck judges you.', cassette: 'You reminisce over the mixtape.', vhs: 'Be kind, rewind.', actionfig: 'The action figure strikes a heroic pose.', gnome: 'The garden gnome watches, unblinking.', brick: 'It is a brick. It is very brick.' };
  sfx('hit'); toast('🧸 ' + (lines[s.id] || def.name), 2200);
}
// spawn a world pickup of an item (billboard sprite; walk over to re-collect)
