    if (d.cat === 'junk') w = 6; else if (d.cat === 'food' || d.cat === 'drink') w = 4;
    else if (d.cat === 'quirky') w = 2; else if (d.cat === 'med' || d.cat === 'tool') w = 1;
    else if (d.cat === 'valuable') w = (d.rarity >= 5 ? 0 : 1);   // gold/phones rare; no diamond ring off a pedestrian
