  var left = bagAdd(id, n), got = n - left;
  for (var i = 0; i < left; i++) { var d = spawnItemDrop(id, player.x + (Math.random() - 0.5) * 1.7, player.z + (Math.random() - 0.5) * 1.7, 120); if (d) d.bagFull = true; }
