  var tx2 = -Math.cos(a) * (HALF + 60) + (Math.random() - 0.5) * 160;
  var tz2 = -Math.sin(a) * (HALF + 60) + (Math.random() - 0.5) * 160;
  var d = Math.sqrt((tx2 - sx) * (tx2 - sx) + (tz2 - sz) * (tz2 - sz));
