  g.traverse(function (o) { o.userData.ufo = true; });
  scene.add(g);
  ufo = { mode: 'fly', group: g, hp: 1680, vx: (tx2 - sx) / d * 6.5, vz: (tz2 - sz) / d * 6.5, dist: 0, maxDist: d, vy: 0, spin: 1, smokeT: 0, crashT: 0, alienAt: 0 };
