      var ddx = player.x + Math.cos(a) * (1.5 + dropped * 0.8), ddz = player.z + Math.sin(a) * (1.5 + dropped * 0.8);
      if (isClient()) netToHost({ t: 'dropGun', k: k, x: ddx, z: ddz });   // host owns the shared drop list
      else dropWeapon(k, ddx, ddz);
      state.owned[k] = false;
